if (!ctx.containsKey('asset') || ctx.asset == null) {
  ctx['asset'] = new HashMap();
}
Map asset = ctx.asset;

// asset.last_seen defaults to ingest time
if (!asset.containsKey('last_seen') || asset.last_seen == null) {
  asset['last_seen'] = ctx['@timestamp'];
}

// asset.name fallback chain: asset.name > asset.fqdn short > host.name > agent.name
if (!asset.containsKey('name') || asset.name == null) {
  if (ctx.containsKey('host') && ctx.host != null && ctx.host.containsKey('name') && ctx.host.name != null) {
    asset['name'] = ctx.host.name;
  } else if (ctx.containsKey('agent') && ctx.agent != null && ctx.agent.containsKey('name') && ctx.agent.name != null) {
    asset['name'] = ctx.agent.name;
  }
}

// asset.status default
if (!asset.containsKey('status') || asset.status == null) {
  asset['status'] = 'active';
}

// Sync asset.managed to m_26_14.managed
if (!ctx.containsKey('m_26_14') || ctx.m_26_14 == null) ctx['m_26_14'] = new HashMap();
if (asset.containsKey('managed')) {
  ctx.m_26_14['managed'] = asset.managed;
}
if (asset.containsKey('source')) {
  ctx.m_26_14['hwam_source'] = asset.source;
}

Map asset = ctx.asset;
if (asset.containsKey('component') && asset.component != null && asset.component.toString().length() > 0) return;
String component = null;
if (asset.containsKey('organization') && asset.organization != null) {
  Map org = asset.organization;
  if (org.containsKey('department') && org.get('department') != null && org.get('department').toString().length() > 0) {
    component = org.get('department').toString();
  } else if (org.containsKey('owner') && org.get('owner') != null && org.get('owner').toString().length() > 0) {
    component = org.get('owner').toString();
  }
}
asset['component'] = (component != null) ? component : 'unattributed';

Set junkSerials = new HashSet(['', '0', 'default string', 'to be filled by o.e.m.', 'system serial number', 'none', 'not specified', 'o.e.m.', 'na', 'n/a', 'not available', 'chassis serial number']);
Map asset = ctx.asset;
String keyType = null;
String rawKey = null;

// 1. Hardware serial number
if (asset.containsKey('hardware') && asset.hardware != null) {
  String serial = asset.hardware.get('serial_number');
  if (serial != null && serial.length() > 0 && !junkSerials.contains(serial.toLowerCase().trim())) {
    keyType = 'serial';
    rawKey = serial.toLowerCase().trim();
  }
  // 2. BIOS UUID
  if (keyType == null) {
    String biosUuid = asset.hardware.get('bios_uuid');
    if (biosUuid != null && biosUuid.length() > 0) {
      // Reject all-zeros UUID
      String stripped = biosUuid.replace('-','').replace(' ','').toLowerCase();
      if (!stripped.equals('00000000000000000000000000000000') && stripped.length() >= 32) {
        keyType = 'bios_uuid';
        rawKey = biosUuid.toLowerCase().trim();
      }
    }
  }
}

// 3. Elastic agent ID
if (keyType == null && ctx.containsKey('agent') && ctx.agent != null && ctx.agent.containsKey('id') && ctx.agent.id != null && ctx.agent.id.length() > 0) {
  keyType = 'agent';
  rawKey = ctx.agent.id;
}

// 4. source_id (e.g. CrowdStrike device_id, Tenable uuid)
if (keyType == null && asset.containsKey('source_id') && asset.source_id != null && asset.source_id.length() > 0) {
  keyType = 'source_id:' + (asset.source != null ? asset.source : 'unknown');
  rawKey = asset.source_id;
}

// 5. First MAC address
if (keyType == null) {
  String mac = null;
  if (ctx.containsKey('host') && ctx.host != null && ctx.host.containsKey('mac')) {
    def macField = ctx.host.mac;
    if (macField instanceof List && macField.size() > 0) mac = (String)macField[0];
    else if (macField instanceof String && macField.length() > 0) mac = macField;
  }
  if (mac == null && asset.containsKey('network') && asset.network instanceof List && asset.network.size() > 0) {
    mac = asset.network[0].get('mac');
  }
  if (mac != null && mac.length() > 0) {
    keyType = 'mac';
    rawKey = mac.toLowerCase().replace('-',':');
  }
}

// 6. Hostname fallback
if (keyType == null && asset.containsKey('name') && asset.name != null && asset.name.length() > 0) {
  keyType = 'hostname';
  rawKey = asset.name.toLowerCase();
}

// Store resolution key for fingerprint; skip if asset.id already set
if (keyType != null && (!asset.containsKey('id') || asset.id == null)) {
  ctx['_asset_resolution_key'] = 'm_26_14-asset:' + keyType + ':' + rawKey;
  Map conf = ['serial':0.95,'bios_uuid':0.90,'agent':0.85,'mac':0.70,'hostname':0.40];
  String confKey = keyType.contains(':') ? keyType.substring(0, keyType.indexOf(':')) : keyType;
  asset['_resolution_confidence'] = conf.containsKey(confKey) ? conf.get(confKey) : 0.30;
}

Map assetOs = (ctx.containsKey('asset') && ctx.asset != null) ? ctx.asset.get('os') : null;
Map topOs = ctx.containsKey('os') ? ctx.os : null;

// Ensure top-level os object exists if asset.os has data
if (assetOs != null && assetOs.size() > 0) {
  if (topOs == null) {
    topOs = new HashMap();
    ctx['os'] = topOs;
  }
  // asset.os → top-level os (fill gaps only)
  for (String k : new String[]{'name','version','build','platform','architecture','eol','kernel'}) {
    if (assetOs.containsKey(k) && assetOs.get(k) != null && !topOs.containsKey(k)) {
      topOs.put(k, assetOs.get(k));
    }
  }
}

// top-level os → asset.os (fill gaps in reverse)
if (topOs != null && topOs.size() > 0 && assetOs != null) {
  for (String k : new String[]{'build','eol'}) {
    if (topOs.containsKey(k) && topOs.get(k) != null && !assetOs.containsKey(k)) {
      assetOs.put(k, topOs.get(k));
    }
  }
}

if (!ctx.containsKey('vulnerability') || ctx.vulnerability == null) return;
Map vuln = ctx.vulnerability;
if (vuln.containsKey('age_days') && vuln.get('age_days') != null) return;
if (!vuln.containsKey('first_found') || vuln.get('first_found') == null) return;
try {
  ZonedDateTime ff = ZonedDateTime.parse(vuln.first_found.toString());
  ZonedDateTime ts = ZonedDateTime.parse(ctx['@timestamp'].toString());
  long ageDays = java.time.temporal.ChronoUnit.DAYS.between(ff, ts);
  if (ageDays >= 0) vuln['age_days'] = ageDays;
} catch (Exception e) { /* ignore parse failures */ }
